INSERT INTO `runway_articles` (`id`, `brand_slug`, `brand_name`, `title`, `meta`, `author`, `content`, `main_images_count`, `detail_images_count`, `created_at`) VALUES
(1, 'balenciaga', 'Balenciaga', 'Balenciaga', 'От Пиерпаоло Пичоли', 'FALL 2026 READY-TO-WEAR', '<p>Борбата между миналото и настоящето – и как би могла да изглежда тя – в големите модни къщи е продължаващата история в Париж. Видяхме Джонатан Андерсън да се впуска в Dior, Сара Бъртън да намира своя глас в Givenchy, Майкъл Райдър да преобразява Celine, а Джак Макколоу и Лазаро Ернандес да се забавляват с Loewe. В събота вечер беше ред на Пиерпаоло Пичоли да се справи с наследството на Balenciaga във второто си ревю за модната къща.</p>\r\n<p>Този път Пичоли сякаш беше готов да се хареса на публиката. „Трябваше да направя портрета на света и общността на Balenciaga“, каза той. Завладяващо видео сътрудничество със Сам Левинсън от Euphoria се проведе в затъмнен сет, за което се чу голяма струпване на крещящи фенове, блокиращи Шанз-Елизе отвън.</p>\r\n<p>Първоначалният му разговор с режисьора се въртеше около „намирането на светлината в тъмнината, което е и метафорично за момента, в който всички ние, за нещастие, живеем“, отбеляза той. „Чувствам, че Сам Левинсън е успял да предаде картината на едно поколение през много човешка перспектива, много чувствителна перспектива, без да съди, нито да празнува, а просто да наблюдава, навлизайки по-дълбоко във всеки герой, за да усети връзката и емоцията.“</p>\r\n<p>Пичоли може да жонглира както с легендарния висш кутюрьор от 50-те и 60-те години на миналия век Кристобал Баленсиага, така и с фокуса на Демна върху младежката култура, върху който да наложи собствената си идентичност. Това ревю беше случай на наблюдение коя страна на марката той избира да усили – не изтънчеността на висшата мода от дебюта си миналия сезон, а много по-скоро засилване на силата на дистопичното култово младежко наследство, което Демна е инсталирал.</p>\r\n<p>Всеки креативен директор сега носи отговорността да управлява дадена марка през тежкото рекламно време. Дали този Пичоли е залагал изцяло на това да запази определено глобално племе от демнаци, които харчат в Balenciaga? Е, що се отнася до дрехите, изглеждаше, че е въпрос на едновременно „да“, „не“ и „може би“.</p>\r\n<p>Първата визия беше черно кожено бомбър яке и пола тип „молив“, всичко в едно, с цип от нивото на чатала до врата. С други думи, улична рокля, срещаща се с висша мода. Впечатлението от коравите, леко перверзни герои на Balenciaga, скитащи по нощните клубове, от близкото минало продължи в черно кожено пончо и в момента, в който момиче с мини рокля тип „бомбер“ излезе с ботуши до бедрата. Палта и пуловери с щампи на кадри от Euphoria върху тях също бяха предназначени да се харесат на тази младежка култура.</p>\r\n<p>И все пак не всичко се разви точно така. Кастингът на Пичоли беше по-включващ възрастта и формата на тялото, отколкото повечето парижки ревюта. Неговите идеи за ефекта на светлосянката извадиха италианската му страна. Той показа много драпирани рокли на богини от копринен трикотаж и кадифе, преплитайки ги с обрамчващи лицето кройки, предназначени да се харесат на шикозните възрастни. По същия начин за мъжете имаше парки, палта и палта с пашкуловиден гръб, които изглеждат по-подходящи за зрял мъж.</p>\r\n<p>Неговият подпис с роклите с пайети на ивици, които наистина уловиха светлината, разпознаваемо върна Пичоли към именитата му същност като убийствен кутюрьор за червения килим. Разбира се, отнема време, за да се адаптира една марка комерсиално, особено когато ужасният термин „ актуалност“ се използва толкова много в този климат. Но дали опитът да се продължи да се работи въз основа на известните факти от миналия пазар означава нещо или нищо в тази нова епоха на несигурност? Значителните таланти на Пичоли винаги са включвали способността да разпространява радост и наслада чрез буйното си чувство за цвят и любовта си към женския интелект. Това не се появи на тъмно този сезон, но той трябва да знае, че модният свят все още копнее да го види.</p>', 82, 67, '2026-04-17 20:32:16'),
(4, 'chanel', 'Chanel', 'Chanel', 'От Матийо Блази', 'FALL 2026 READY-TO-WEAR', '<p>Всяко споменаване на Chanel този сезон не е пълно, без да се отбележи хаосът в парижките магазини на модната къща. Тълпата е обзета от желание; има съобщения за редактори, ръководители и модели, които чакат с часове, за да направят покупките си, за жени, купуващи няколко чифта обувки, дори само една чанта, проектирана от Matthieu Blazy. Очевидно това е неизречено ограничение, въпреки че, разбира се, се предлагат и толкова чанти тип „колона“, колкото човек иска. През 20-те години, в които посещавам парижките ревюта, никоя друга дебютна колекция не е привлякла толкова много внимание от страна на модните експерти.</p>\r\n<p>В тази суматоха Блейзи изпрати тази вечер втория си сезон готови дрехи за френската модна къща, макар че технически това е четвъртото му шоу, след дебюта през октомври, декемврийското шоу на Metiers d\'Art в Ню Йорк и сензацията от висша мода през януари. Гран Пале изглеждаше като строителна площадка с осветени в основни цветове кранове. „Интересуваше ме идеята да изградя мечта, едно незавършено произведение“, каза той.</p>\r\n<p>Всъщност, Блази бързо преориентира Chanel. Дори когато се обръща към десетилетията иновации на Коко – „начинът, по който тя е взела дрехи от работническата класа, е променила контекста и е казала „това също е лукс““ – той е решен да премахне всичко старомодно в модната къща, която тя основава през 1910 г. Това означава, че в един момент е цитирал нейните модели с колан и падаща талия от 20-те години на миналия век, а в следващия е изпращал блузони като съвременни и „актуални“, както всичко, което е излизало от подиума на Chanel през годините.</p>\r\n<p>Обяснявайки се зад кулисите, Блази цитира наблюдение, което Шанел прави пред френския вестник „Фигаро“ през 50-те години на миналия век. „Имаме нужда от рокли, които пълзят, и рокли, които летят, защото пеперудата не отива на пазара, а гъсеницата не отива на бала.“ Това му дава подготовка за ревю, което започва с най-простите черни пола от оребрена смес от мериносова вълна и коприна със златни копчета и се развива в серия от преливащи се визии, изработени от щампована верижна ризница и туид trompe l\'oeil; функция и измислица едно до друго. Междувременно той внимателно проучва онези визии с колан и падаща талия, които удължават торса, създавайки разкошен, неструктуриран и да, гъсеничен отговор на съкратените якета Bar на Джонатан Андерсън в Dior.</p>\r\n<p>Отвъд силуетите, тази колекция беше витрина за забележителните постижения, които ателиетата на Chanel са способни да постигнат на ниво плата: комплект от топ и пола без ръкави с перлени пайети, вплетени в дизайна, поли с шевове „екшън живопис“, блестяща рокля от лурексов кадифе, украсена с бродерии, гъсеницата, най-накрая превърната в пеперуда. Разкошните гледки към Гран Пале, макар и изключително впечатляващи, не винаги отдаваха дължимото на тези дрехи и тяхната изящност. Те се наблюдават най-добре в изключително близък план, където можете да обърнете подгъва, за да видите допълващата подплата на якето, или да оцените почти безтегловността на роклята.</p>\r\n<p>Блейзи приема новата си работа много сериозно, но носи отговорността забележително леко. Тези бродирани рокли сякаш почти изчезнаха. И той даде последната дума на Коко. На нея се приписва новаторството на малката черна рокля; тази беше с кройка от флуиден, непретенциозен трикотаж, възможно най-семпла отпред, но с открит нисък гръб, подчертан от камелия, окачена между лопатките. „Това е Chanel за мен“, каза той, „тази тиха революция, но бум .“</p>', 79, 100, '2026-04-18 02:01:35');

